graphql.query:
mutation Login($companyId: String!, $usernameOrEmail: String!, $password: String!) {
  login(companyId: $companyId, usernameOrEmail: $usernameOrEmail, password: $password) {
    errors { field message }
    user { id name email role status companyId company { id name slug } }
  }
}

mutation LoginSuperAdmin($usernameOrEmail: String!, $password: String!) {
  loginSuperAdmin(usernameOrEmail: $usernameOrEmail, password: $password) {
    errors { field message }
    user { id email username role status companyId }
  }
}

query Me {
  me {
    id name email username role status
    companyId company { id name slug }
    countAssignedProgram countAssignedBootcamp isMentor
  }
}

mutation ForgotPassword($email: String!, $slug: String, $captcha: String) {
  forgotPassword(email: $email, slug: $slug, captcha: $captcha)
}

mutation UpdateMyPassword($input: UpdateMyPasswordInput!) {
  updateMyPassword(input: $input) { id email }
}

query Companies($page: Float, $limit: Float, $search: String, $status: [String!]) {
  companies(page: $page, limit: $limit, search: $search, status: $status, orderColumn: "createdAt", orderBy: "DESC") {
    id name slug email status maxActiveEmployee maxStorage
    countEmployee countActiveEmployee countVideoCourse countClass
  }
  countCompanies(search: $search, status: $status)
}

mutation CreateCompany($input: CreateCompanyParam!) {
  createCompany(input: $input) { id name slug status }
}

mutation UpdateCompany($id: String!, $input: CreateCompanyParam!) {
  updateCompany(id: $id, input: $input) { id name slug status }
}

mutation ToggleCompany($id: String!) {
  activateCompany(id: $id)
  # inactivateCompany(id: $id)
}

mutation UpdateVCPerm($id: String!, $input: CompanyVideoCoursePermissionInput!) {
  updateCompanyVideoCoursePermission(id: $id, input: $input) { id maxVideoCourse videoCourseExpiredDate }
}

query Employees($page: Float, $limit: Float, $search: String, $status: [String!], $divisionIds: [String!]) {
  employees(page: $page, limit: $limit, search: $search, status: $status, divisionIds: $divisionIds, orderColumn: "name", orderBy: "ASC") {
    id name email employeeId status divisionId
    division { id name } angkatan { id name }
    countAssignedProgram countFinishedProgram averageTotalScore
  }
  countEmployees(search: $search, status: $status, divisionIds: $divisionIds)
}

query EmployeeById($id: String!) {
  employeeById(id: $id) { id name email status division { id name } }
}

mutation createEmployee($input: EmployeeInput!) {
  createEmployee(input: $input) {
    id
    __typename
  }
}

mutation updateEmployee($id: String!, $input: EmployeeInput!) {
  updateEmployee(id: $id, input: $input) {
    id name email phoneNumber
  }
}

mutation MoveDivision($employeeIds: [String!]!, $divisionId: String!) {
  updateEmployeesDivision(employeeIds: $employeeIds, divisionId: $divisionId)
}

query Divisions($page: Float, $limit: Float, $search: String) {
  divisions(page: $page, limit: $limit, search: $search, orderColumn: "name", orderBy: "ASC") {
    id name description countEmployees
  }
  countDivisions(search: $search)
}

mutation CreateDivision($input: DivisionInput!) {
  createDivision(input: $input) { id name description }
}

query Programs($page: Float, $limit: Float, $search: String, $type: String) {
  programs(page: $page, limit: $limit, search: $search, type: $type, orderColumn: "createdAt", orderBy: "DESC") {
    id title type isSequential countChapters countContents countAssignedEmployee
  }
  countPrograms(search: $search, type: $type)
}

mutation CreateProgram($input: ProgramInput!) {
  createProgram(input: $input) { id title type isSequential }
}

mutation CreateChapter($input: ChapterInput!) {
  createChapter(input: $input) { id title order }
}

mutation CreateContent($input: ContentInput!) {
  createContent(input: $input) { id title type order }
}

mutation CreateQuestion($input: QuestionInput!) {
  createQuestion(input: $input) { id question options answers }
}

mutation AssignProgram($input: AssignProgramInput!) {
  assignProgram(input: $input)
}

query Chapters($programId: String!) {
  chaptersByProgramId(programId: $programId) {
    id title order countContents contents { id title type order }
  }
}

query MyUserProgram($status: [String!]!, $type: [String!]!, $page: Float, $limit: Float, $search: String) {
  myUserProgram(status: $status, type: $type, page: $page, limit: $limit, search: $search) {
    id status startDate endDate isFinished countPercentageProgress avgScore
    program { id title type countChapters countContents }
  }
  countMyUserProgram(status: $status, type: $type)
}

query Progress($userProgramId: String!) {
  userProgressChaptersByUserProgramId(userProgramId: $userProgramId) {
    id title order countContents countFinishedContent
    contents { id title type order isComplete }
  }
}

query Content($id: String!) {
  contentById(id: $id) {
    id title type article videoUrl duration isComplete
    questions { id question options }
  }
}

mutation SubmitContentLog($contentId: String!) {
  submitContentLog(contentId: $contentId) { id }
}

mutation SubmitTestLog($contentId: String!, $answers: [ContentLogAnswerInput!]!) {
  submitTestLog(contentId: $contentId, answers: $answers) { id }
}

query VideoCourses($page: Float, $limit: Float, $search: String, $categoryId: [Float!]) {
  videoCourses(page: $page, limit: $limit, search: $search, categoryId: $categoryId) {
    id title briefDescription access avgRating category { id name }
  }
  countVideoCourses(search: $search, categoryId: $categoryId)
}

query MyVideoCourses($param: InputBaseQuery) {
  myVideoCourses(param: $param) { id title access avgRating }
}

mutation AssignVC($videoCourseId: Float!, $userIds: [String!]!, $endDate: DateTime) {
  assignUserProgramByVideoCourseId(videoCourseId: $videoCourseId, userIds: $userIds, endDate: $endDate) { id status }
}

mutation RateVC($videoCourseId: Float!, $rating: Float!, $feedback: String!) {
  rateVideoCourse(videoCourseId: $videoCourseId, rating: $rating, feedback: $feedback)
}

query Bootcamps($param: InputBaseQuery!) {
  bootcamps(param: $param) { id title startedAt finishedAt countAssignedUser }
  countBootcamps(param: $param)
}

query MyBootcamps($param: BootcampBaseQuery!) {
  myBootcamps(param: $param) { id title startedAt finishedAt }
  countMyBootcamps(param: $param)
}

mutation CreateBootcamp($input: InputBootcamp!) {
  createBootcamp(input: $input) { id title startedAt finishedAt }
}

mutation CreateBootcampContent($input: InputBootcampContent!) {
  createBootcampContent(input: $input) { id title liveClassTime }
}

mutation CreateBootcampQuiz($input: InputBootcampQuiz!) {
  createBootcampQuiz(input: $input) { id title type deadline }
}

mutation CreateBootcampQuestion($input: InputBootcampQuestion!) {
  createBootcampQuestion(input: $input) { id question }
}

mutation CreateBootcampSubmission($input: InputBootcampSubmission!) {
  createBootcampSubmission(input: $input) { id title deadline }
}

mutation AssignUserBootcamp($bootcampId: String!, $userIds: [String!]!) {
  assignUserBootcamp(bootcampId: $bootcampId, userIds: $userIds)
}

mutation Absen($input: BootcampContentLogInput!) {
  createBootcampContentLog(input: $input) { id action }
}

mutation SubmitQuiz($input: BootcampQuizLogInput!) {
  submitNewQuizLog(input: $input) { id status score }
}

mutation SubmitProject($input: CreateBootcampSubmissionLog!) {
  submitBootcampSubmission(input: $input) { id }
}

mutation FinalScore($bootcampBatchId: String!) {
  generateFinalScore(bootcampBatchId: $bootcampBatchId) { userId finalScore }
}

query Announcements($page: Float, $limit: Float, $search: String) {
  announcements(page: $page, limit: $limit, search: $search, orderColumn: "createdAt", orderBy: "DESC") {
    id title content isForAllEmployee createdAt
  }
  countAnnouncement(search: $search)
}

mutation CreateAnnouncement($input: AnnouncementInput!) {
  createAnnouncement(input: $input) { id title }
}

query MyAnnouncements($lastId: String, $limit: Float) {
  myUserAnnouncement(lastId: $lastId, limit: $limit) {
    id isRead announcement { id title content createdAt }
  }
}

mutation MarkRead($announcementIds: [String!]!) {
  setIsReadAnnouncement(announcementIds: $announcementIds)
}

query Forums($query: ForumBaseQuery!) {
  forums(query: $query) { id title text type }
  countForums(query: $query)
}

mutation CreateForum($input: InputForum!) {
  createForum(input: $input) { id text }
}

mutation Vote($forumId: String!, $value: Float!) {
  upForumVotes(forumId: $forumId, value: $value) { id }
}

query Medias($type: String, $param: InputBaseQuery) {
  medias(type: $type, param: $param) { id title type mimeType size url status }
  countMedias(type: $type)
}

mutation CreateRawMedia($title: String!, $fileName: String!, $fileSize: Float!, $mimeType: String!) {
  createRawMedia(title: $title, fileName: $fileName, fileSize: $fileSize, mimeType: $mimeType) { id title status }
}

query MentorBootcamp($query: InputBaseQuery!) {
  mentorBootcamp(query: $query) { id title startedAt finishedAt }
  countMentorBootcamp(query: $query)
}

query Mentors($bootcampId: String!, $query: UserBaseQuery) {
  assignedMentor(bootcampId: $bootcampId, query: $query) { id name email }
  countAssignedMentor(bootcampId: $bootcampId, query: $query)
  unassignedMentor(bootcampId: $bootcampId, query: $query) { id name email }
  countUnassignedMentor(bootcampId: $bootcampId, query: $query)
}

mutation AssignMentor($bootcampId: String!, $userIds: [String!]!) {
  assignMentor(bootcampId: $bootcampId, userIds: $userIds) { id }
}

mutation UnassignMentor($bootcampId: String!, $userIds: [String!]!) {
  unassignMentor(bootcampId: $bootcampId, userIds: $userIds) { id }
}

query MentorTasks($q: BootcampQuizBaseQuery!, $s: BootcampSubmissionBaseQuery!) {
  mentorBootcampQuiz(query: $q) { id title type }
  mentorBootcampSubmission(query: $s) { id title type }
}

mutation EssayGrading($id: String!, $input: BootcampEssayGradingInput!) {
  essayGrading(id: $id, input: $input) { id score }
}

mutation GradeSubmission($id: String!, $input: UserSubmissionUpdate!) {
  gradeUserSubmission(id: $id, input: $input) { id }
}

mutation FinishGrading($quizId: String!, $submissionId: String!) {
  quizFinishGradingToggle(id: $quizId) { id isFinishGrading }
  submissionFinishGradingToggle(id: $submissionId) { id isGradingFinish }
}

query LogByCompany($input: InputBaseQuery!, $events: [String!], $entities: [String!], $employeeIds: [String!]) {
  userActivityLogByCompanyId(input: $input, events: $events, entities: $entities, employeeIds: $employeeIds) {
    id
  }
  countUserActivityLogByCompanyId(input: $input, events: $events, entities: $entities, employeeIds: $employeeIds)
}

query Log($input: InputBaseQuery!, $companyIds: [String!], $roles: [String!]) {
  userActivityLog(input: $input, companyIds: $companyIds, roles: $roles) { id }
  countUserActivityLog(input: $input, companyIds: $companyIds, roles: $roles)
}

mutation ExportLog($events: [String!], $entities: [String!], $employeeIds: [String!]) {
  exportUserActivityLog(events: $events, entities: $entities, employeeIds: $employeeIds)
}
